{
  "title": "Introduction to Python Programming for Game Development",
  "description": "This course is designed for beginners who are interested in learning Python programming with a focus on game development. Through four comprehensive modules, learners will gain the foundational skills necessary to create simple games using Python.",
  "modules": [
    {
      "id": "module_1",
      "title": "Getting Started with Python",
      "description": "Learn the basics of Python programming, including installation, syntax, data types, and control structures. This module will provide a solid foundation for further game development."
    },
    {
      "id": "module_2",
      "title": "Introduction to Game Development Concepts",
      "description": "Explore the fundamental concepts of game development, including game loops, event handling, and graphics. This module will introduce you to the principles of creating interactive applications."
    },
    {
      "id": "module_3",
      "title": "Building Your First Game",
      "description": "Apply your knowledge by creating a simple game using Python. This module will guide you through the process of designing, coding, and testing your first game project."
    },
    {
      "id": "module_4",
      "title": "Enhancing Your Game and Next Steps",
      "description": "Learn how to add features and improve your game, such as sound, scoring, and user interface elements. This module will also provide resources for further learning and development in Python game programming."
    }
  ]
}
